SELECT COUNT(*) AS synced_movements_count
FROM movements
WHERE is_synced = 1;

SELECT AVG(metric_value) AS average_acceleration
FROM movement_metrics
WHERE metric_name = 'acceleration' AND is_calculated = 1;

SELECT metric_name
FROM user_metrics
WHERE user_id = 0 AND time_period = 'daily';

SELECT DISTINCT user_id
FROM movements
WHERE is_synced = 1;

SELECT COUNT(*) AS annotation_count
FROM movement_annotations
WHERE annotated_by = 1;
